import { ipcMain } from 'electron';
import {
  IPC_CHANNELS,
  ServerIdSchema,
  DatabasePreflightSchema,
  CreateDatabaseSchema,
  DatabaseIdSchema,
  DatabaseToggleAccessSchema,
  DatabaseDeleteSchema,
  DatabaseCredentialsSchema,
  DatabaseLogsSchema,
  DatabaseRetrySchema,
  DatabaseVerifySchema,
  DatabaseRotateSchema,
  DatabaseImportPreviewSchema,
  DatabaseImportStartSchema,
  DatabaseImportListTablesSchema,
  type ApiResult,
} from './types';
import { queries, type DatabaseRecord, type DatabaseOperationRecord } from '../db';
import { licenseService } from '../services/LicenseService';
import { databaseService } from '../services/DatabaseService';
import { databaseImportService } from '../services/DatabaseImportService';
import type { DatabaseCreateRequest } from '../services/DatabaseService';

interface RendererDatabase {
  id: string;
  serverId: string;
  name: string;
  type: DatabaseRecord['type'];
  status: DatabaseRecord['status'];
  access: DatabaseRecord['access'];
  version: string | null;
  createdAt: number;
  updatedAt: number;
  lastActivityAt: number | null;
  connection?: {
    host: string;
    port: number;
    username: string;
    database: string;
    connectionStringMasked: string;
  } | null;
  extras?: Record<string, unknown> | null;
  stats?: Record<string, unknown> | null;
  lastError: string | null;
}

interface RendererDatabaseStatus {
  status: DatabaseRecord['status'];
  currentPhase?: string;
  phaseIndex?: number;
  totalPhases?: number;
  currentCommand?: string;
  commandStatus?: 'pending' | 'running' | 'success' | 'failed';
  error?: string | null;
}

type DatabaseRunLogEntry = {
  timestamp: number;
  phase: string;
  command: string;
  status: 'pending' | 'running' | 'success' | 'failed';
  output?: string;
  error?: string;
};

const safeJsonParse = <T>(raw: string | null): T | null => {
  if (!raw) return null;
  try {
    return JSON.parse(raw) as T;
  } catch (error) {
    console.warn('[database ipc] Failed to parse JSON payload', error);
    return null;
  }
};

const maskConnectionString = (value: string | undefined): string | undefined => {
  if (!value) return value;
  const match = value.match(/^(.*:\/\/[^:]+):([^@]+)@(.*)$/);
  if (!match) {
    return value;
  }
  return `${match[1]}:***@${match[3]}`;
};

const requireDatabaseAccess = () => {
  const access = licenseService.canUseDatabases();
  if (!access.allowed) {
    throw new Error(access.reason || 'Database provisioning is available for licensed users.');
  }
};

const buildRendererDatabase = async (record: DatabaseRecord): Promise<RendererDatabase> => {
  let connection: RendererDatabase['connection'] | null = null;
  const metadata = safeJsonParse<{ extras?: Record<string, unknown> }>(record.metadata);
  const stats = safeJsonParse<Record<string, unknown>>(record.stats);
  if (record.encrypted_credentials) {
    try {
      const credentials = await databaseService.getCredentials(record.id);
      connection = {
        host: credentials.host,
        port: credentials.port,
        username: credentials.username,
        database: credentials.database,
        connectionStringMasked: maskConnectionString(credentials.connectionString) ?? credentials.connectionString,
      };
    } catch (error) {
      console.warn('[database ipc] Unable to decrypt credentials for database %s', record.id, error);
    }
  }

  return {
    id: record.id,
    serverId: record.server_id,
    name: record.name,
    type: record.type,
    status: record.status,
    access: record.access,
    version: record.version,
    createdAt: record.created_at,
    updatedAt: record.updated_at,
    lastActivityAt: record.last_activity_at ?? null,
    connection,
    extras: metadata?.extras ?? null,
    stats: stats ?? null,
    lastError: record.last_error,
  };
};

const buildStatusFromOperation = (record: DatabaseRecord, operation?: DatabaseOperationRecord | null): RendererDatabaseStatus => {
  if (!operation) {
    return {
      status: record.status,
      error: record.last_error,
    };
  }

  const meta = safeJsonParse<{ phases?: { name: string; commands: string[] }[] }>(operation.meta);
  const log = safeJsonParse<DatabaseRunLogEntry[]>(operation.log) ?? [];
  const lastEntry = [...log].reverse().find((entry) => entry.status === 'running' || entry.status === 'failed' || entry.status === 'success');

  const phaseIndex = lastEntry && meta?.phases
    ? meta.phases.findIndex((phase) => phase.name === lastEntry.phase)
    : undefined;

  return {
    status: record.status,
    currentPhase: lastEntry?.phase,
    phaseIndex: phaseIndex !== undefined && phaseIndex >= 0 ? phaseIndex + 1 : undefined,
    totalPhases: meta?.phases?.length,
    currentCommand: lastEntry?.command,
    commandStatus: lastEntry?.status,
    error: operation.error_message ?? record.last_error,
  };
};

export function registerDatabaseHandlers() {
  ipcMain.handle(IPC_CHANNELS.DATABASES_GET_BY_SERVER, async (_event, input): Promise<ApiResult<RendererDatabase[]>> => {
    try {
      const { id } = ServerIdSchema.parse(input);
      const records = queries.getDatabasesByServer(id);
      const payload = await Promise.all(records.map((record) => buildRendererDatabase(record)));
      return { success: true, data: payload };
    } catch (error) {
      console.error('[database ipc] Failed to list databases', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.DATABASES_PREFLIGHT, async (_event, input): Promise<ApiResult<Awaited<ReturnType<typeof databaseService.runPreflight>>>> => {
    try {
      requireDatabaseAccess();
      const validated = DatabasePreflightSchema.parse(input);
      const preflightPayload: DatabaseCreateRequest = {
        serverId: validated.serverId,
        name: validated.name ?? `db-${Date.now()}`,
        type: validated.type,
        engineVersion: validated.engineVersion,
        access: validated.access,
        requestedPort: validated.requestedPort,
        advanced: validated.advanced,
      };
      const result = await databaseService.runPreflight(preflightPayload);
      return { success: true, data: result };
    } catch (error) {
      console.error('[database ipc] Preflight failed', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.DATABASES_CREATE, async (_event, input): Promise<ApiResult<{ databaseId: string }>> => {
    try {
      requireDatabaseAccess();
      const parsed = CreateDatabaseSchema.parse(input);
      const name = parsed.name as string;
      const createPayload: DatabaseCreateRequest = {
        serverId: parsed.serverId,
        name,
        type: parsed.type,
        engineVersion: parsed.engineVersion,
        access: parsed.access,
        requestedPort: parsed.requestedPort,
        advanced: parsed.advanced,
      };
      const result = await databaseService.createDatabase(createPayload);
      return { success: true, data: result };
    } catch (error) {
      console.error('[database ipc] Create database failed', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.DATABASES_STATUS, async (_event, input): Promise<ApiResult<RendererDatabaseStatus>> => {
    try {
      requireDatabaseAccess();
      const validated = DatabaseIdSchema.parse(input);
      const record = queries.getDatabaseById(validated.databaseId);
      if (!record || record.server_id !== validated.serverId) {
        throw new Error('Database not found');
      }
      const operation = record.last_operation_id ? queries.getDatabaseOperationById(record.last_operation_id) : undefined;
      return { success: true, data: buildStatusFromOperation(record, operation) };
    } catch (error) {
      console.error('[database ipc] Status lookup failed', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.DATABASES_ROTATE, async (_event, input): Promise<ApiResult<any>> => {
    try {
      requireDatabaseAccess();
      const validated = DatabaseRotateSchema.parse(input);
      const payload = await databaseService.rotateCredentials(validated.databaseId);
      return { success: true, data: payload };
    } catch (error) {
      console.error('[database ipc] Rotate credentials failed', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.DATABASES_TOGGLE_ACCESS, async (_event, input): Promise<ApiResult<{ success: boolean }>> => {
    try {
      requireDatabaseAccess();
      const validated = DatabaseToggleAccessSchema.parse(input);
      const result = await databaseService.updateExternalAccess({
        serverId: validated.serverId,
        databaseId: validated.databaseId,
        enabled: validated.enabled,
        cidrAllowList: validated.cidrAllowList,
        reason: validated.reason,
      });
      return { success: true, data: result };
    } catch (error) {
      console.error('[database ipc] Toggle access failed', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.DATABASES_DELETE, async (_event, input): Promise<ApiResult<{ success: boolean }>> => {
    try {
      requireDatabaseAccess();
      const validated = DatabaseDeleteSchema.parse(input);
      const result = await databaseService.deleteDatabase(validated.databaseId, validated.force ?? false);
      return { success: true, data: result };
    } catch (error) {
      console.error('[database ipc] Delete database failed', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.DATABASES_CREDENTIALS, async (_event, input): Promise<ApiResult<any>> => {
    try {
      requireDatabaseAccess();
      const validated = DatabaseCredentialsSchema.parse(input);
      const credentials = await databaseService.getCredentials(validated.databaseId);
      return { success: true, data: credentials };
    } catch (error) {
      console.error('[database ipc] Fetch credentials failed', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.DATABASES_LOGS, async (_event, input): Promise<ApiResult<DatabaseRunLogEntry[]>> => {
    try {
      requireDatabaseAccess();
      const validated = DatabaseLogsSchema.parse(input);
      const record = queries.getDatabaseById(validated.databaseId);
      if (!record) {
        throw new Error('Database not found');
      }
      const operations = queries.getDatabaseOperationsByDatabase(record.id, validated.limit ?? 50);
      const latest = operations[0];
      const logEntries = safeJsonParse<DatabaseRunLogEntry[]>(latest?.log) ?? [];
      return { success: true, data: logEntries };
    } catch (error) {
      console.error('[database ipc] Fetch logs failed', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.DATABASES_VERIFY, async (_event, input): Promise<ApiResult<{ connectionOk: boolean }>> => {
    try {
      requireDatabaseAccess();
      const validated = DatabaseVerifySchema.parse(input);
      const record = queries.getDatabaseById(validated.databaseId);
      if (!record) {
        throw new Error('Database not found');
      }
      // For the initial implementation, verification simply checks decrypted credentials exist
      await databaseService.getCredentials(record.id);
      return { success: true, data: { connectionOk: true } };
    } catch (error) {
      console.error('[database ipc] Verification failed', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.DATABASES_RETRY, async (_event, input): Promise<ApiResult<{ status: DatabaseRecord['status']; operationId: string; databaseId: string }>> => {
    try {
      requireDatabaseAccess();
      const validated = DatabaseRetrySchema.parse(input);
      const record = queries.getDatabaseById(validated.databaseId);
      if (!record || record.server_id !== validated.serverId) {
        throw new Error('Database not found');
      }

      const { operationId } = await databaseService.retryProvision(record.id);

      return {
        success: true,
        data: {
          status: 'provisioning',
          operationId,
          databaseId: record.id,
        },
      };
    } catch (error) {
      console.error('[database ipc] Retry provisioning failed', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.DATABASES_IMPORT_PREVIEW, async (_event, input): Promise<ApiResult<Awaited<ReturnType<typeof databaseImportService.previewCsv>>>> => {
    try {
      requireDatabaseAccess();
      const validated = DatabaseImportPreviewSchema.parse(input);
      const result = await databaseImportService.previewCsv(validated);
      return { success: true, data: result };
    } catch (error) {
      console.error('[database import ipc] Preview failed', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.DATABASES_IMPORT_TABLES, async (_event, input): Promise<ApiResult<Awaited<ReturnType<typeof databaseImportService.listTables>>>> => {
    try {
      requireDatabaseAccess();
      const validated = DatabaseImportListTablesSchema.parse(input);
      const tables = await databaseImportService.listTables(validated.serverId, validated.databaseId);
      return { success: true, data: tables };
    } catch (error) {
      console.error('[database import ipc] List tables failed', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.DATABASES_IMPORT_START, async (_event, input): Promise<ApiResult<Awaited<ReturnType<typeof databaseImportService.startImport>>>> => {
    try {
      requireDatabaseAccess();
      const validated = DatabaseImportStartSchema.parse(input);
      const summary = await databaseImportService.startImport(validated);
      return { success: true, data: summary };
    } catch (error) {
      console.error('[database import ipc] Start import failed', error);
      return { success: false, error: String(error) };
    }
  });
}
